"use client";

import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";
import { useSession } from "next-auth/react";
import { useEffect, useState } from "react";
import { Icons } from "@/components/assets/icons";
import { GitHubOAuthButton } from "@/components/buttons/github-oauth-button";
import { buttonVariants } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { routes } from "@/config/routes";
import { SEARCH_PARAM_KEYS } from "@/config/search-param-keys";
import { cn } from "@/lib/utils";

// Simple client-only wrapper component
const ClientOnly = ({ children }: { children: React.ReactNode }) => {
  const [hasMounted, setHasMounted] = useState(false);

  useEffect(() => {
    setHasMounted(true);
  }, []);

  if (!hasMounted) {
    return null;
  }

  return <>{children}</>;
};

export default function GitHubConnectPage() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const { data: session, update: updateSession, status } = useSession();
  const [isProcessing, setIsProcessing] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Process GitHub connection response if parameters are present
  useEffect(() => {
    const processConnection = async () => {
      // Only process if authenticated and not already processing
      if (status !== "authenticated" || isProcessing) return;

      // Check if searchParams exists before trying to use it
      if (!searchParams) return;

      const code = searchParams.get(SEARCH_PARAM_KEYS.statusCode);
      if (!code) return;

      try {
        setIsProcessing(true);

        // Connections are now handled directly by the NextAuth callback
        // Just force a session update to make sure we have the latest data
        await updateSession({ force: true });

        setIsSuccess(true);

        // Redirect to settings after a short delay
        setTimeout(() => {
          const nextUrl = searchParams.get(SEARCH_PARAM_KEYS.nextUrl);
          router.push(nextUrl ?? routes.settings.account);
        }, 3000);
      } catch (error) {
        console.error("Error connecting GitHub:", error);
        setError(error instanceof Error ? error.message : "Failed to connect GitHub account");
      } finally {
        setIsProcessing(false);
      }
    };

    processConnection();
  }, [searchParams, status, isProcessing, updateSession, router]);

  const isConnected = !!session?.user?.githubUsername;

  if (status === "loading") {
    return (
      <div className="container mx-auto flex min-h-screen max-w-xl flex-col items-center justify-center">
        <Card className="w-full">
          <CardHeader className="space-y-1">
            <CardTitle className="text-2xl">Connecting GitHub Account</CardTitle>
            <CardDescription>Please wait while we process your GitHub connection</CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col items-center justify-center space-y-4 py-8">
            <Icons.spinner className="h-8 w-8 animate-spin text-primary" />
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <ClientOnly>
      <div className="container mx-auto flex min-h-screen max-w-xl flex-col items-center justify-center">
        <Card className="w-full">
          <CardHeader className="space-y-1">
            <CardTitle className="text-2xl">GitHub Connection</CardTitle>
            <CardDescription>
              {isSuccess
                ? "Your GitHub account has been connected successfully!"
                : isConnected
                  ? "Your GitHub account is already connected"
                  : "Connect your GitHub account to access repository features"}
            </CardDescription>
          </CardHeader>
          <CardContent className="flex flex-col items-center justify-center space-y-4 py-8">
            {error ? (
              <div className="rounded-lg bg-destructive/10 p-4 text-destructive">
                <p>{error}</p>
              </div>
            ) : isSuccess ? (
              <div className="flex flex-col items-center justify-center space-y-4">
                <div className="h-16 w-16 rounded-full bg-green-100 flex items-center justify-center text-green-500">
                  <svg
                    xmlns="http://www.w3.org/2000/svg"
                    fill="none"
                    viewBox="0 0 24 24"
                    stroke="currentColor"
                    className="h-10 w-10"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={2}
                      d="M5 13l4 4L19 7"
                    />
                  </svg>
                </div>
                <p className="text-center">
                  Successfully connected to GitHub as{" "}
                  <strong>{session?.user?.githubUsername}</strong>
                </p>
                <p className="text-center text-sm text-muted-foreground">
                  Redirecting to your profile settings...
                </p>
              </div>
            ) : isConnected ? (
              <div className="flex flex-col items-center justify-center space-y-4">
                <Icons.github className="h-16 w-16" />
                <p className="text-center">
                  Your account is connected to GitHub as{" "}
                  <strong>{session?.user?.githubUsername}</strong>
                </p>
              </div>
            ) : (
              <div className="flex flex-col items-center justify-center space-y-4">
                <Icons.github className="h-16 w-16" />
                <p className="text-center">Connect your GitHub account to get started</p>
                <GitHubOAuthButton
                  className="w-full"
                  isConnected={isConnected}
                  githubUsername={session?.user?.githubUsername}
                />
              </div>
            )}
          </CardContent>
          <CardFooter className="flex justify-center">
            <Link
              href={routes.settings.profile}
              className={cn(buttonVariants({ variant: "outline" }))}
            >
              Back to Settings
            </Link>
          </CardFooter>
        </Card>
      </div>
    </ClientOnly>
  );
}

import type { Metadata } from "next";
import { constructMetadata } from "@/config/metadata";

export const metadata: Metadata = constructMetadata({
  title: "Connect GitHub",
  description:
    "Connect your GitHub account to access repository features and collaborate on projects.",
  noIndex: true,
});

export default function GitHubConnectLayout({ children }: { children: React.ReactNode }) {
  return children;
}

import { Octokit } from "@octokit/rest";
import { eq } from "drizzle-orm";
import { cache } from "react";
import { siteConfig } from "@/config/site-config";
import { env } from "@/env";
import { logger } from "@/lib/logger";
import { db } from "@/server/db";
import { users } from "@/server/db/schema";

/**
 * GitHub profile information with repository permissions
 */
export interface GitHubProfile {
  login: string;
  avatar_url: string;
  html_url: string;
  name: string;
  bio: string;
  company: string | null;
  blog: string;
  location: string | null;
  email: string | null;
  public_repos: number;
  followers: number;
  following: number;
  permission: string;
}

// Conditionally initialize Octokit
let octokit: Octokit | null = null;
let isInitialized = false;

if (env.NEXT_PUBLIC_FEATURE_GITHUB_API_ENABLED) {
  if (!env.GITHUB_ACCESS_TOKEN) {
    if (!isInitialized) {
      logger.error("GitHub API feature is enabled, but GITHUB_ACCESS_TOKEN is missing.");
      isInitialized = true;
    }
  } else {
    octokit = new Octokit({
      auth: env.GITHUB_ACCESS_TOKEN,
    });
    if (!isInitialized) {
      isInitialized = true;
    }
  }
} else {
  // logger.debug("GitHub API feature is disabled.");
}

// Export the potentially null octokit instance
export { octokit };

/** Placeholder email used for stub users created when manually adding a collaborator */
export const pendingCollaboratorEmail = (username: string) =>
  `github:${username.toLowerCase()}@pending.local`;

// --- Helper Function to check if service is enabled ---
const isGitHubServiceEnabled = (): boolean => {
  if (!octokit) {
    if (env.NEXT_PUBLIC_FEATURE_GITHUB_API_ENABLED) {
      // Log error only if the feature was supposed to be enabled but failed init
      logger.error(
        "GitHub Service was enabled but failed to initialize (likely missing token). Returning disabled state."
      );
    }
    return false;
  }
  return true;
};
// ----------------------------------------------------

interface GitHubAccessParams {
  githubUsername: string;
}

// Cache for 5 minutes
export const getRepo = cache(async (owner?: string, repo?: string) => {
  if (!isGitHubServiceEnabled()) {
    logger.debug("GitHub Service disabled, skipping getRepo.");
    return null;
  }
  try {
    // Use provided values or fall back to siteConfig defaults
    const repoOwner = owner || siteConfig.repo.owner;
    const repoName = repo || siteConfig.repo.name;

    const response = await octokit?.rest.repos.get({
      owner: repoOwner,
      repo: repoName,
    });

    if (!response?.data) {
      logger.error("No response data from GitHub API");
      return null;
    }

    return response.data;
  } catch (error) {
    logger.error("Error fetching GitHub repo:", error);
    return null;
  }
});

/**
 * Grants access to the private repository for a GitHub user
 */
export async function grantGitHubAccess({ githubUsername }: GitHubAccessParams) {
  if (!isGitHubServiceEnabled()) {
    logger.warn("GitHub Service disabled, skipping grantGitHubAccess.");
    // Decide on return type: throw error or return specific status?
    // Returning false for now, indicating failure/disabled.
    return false;
  }

  logger.info("Starting GitHub access grant", {
    githubUsername,
  });

  // Token existence check is implicitly handled by isGitHubServiceEnabled()

  if (!githubUsername) {
    logger.error("GitHub username missing");
    throw new Error("GitHub username is required");
  }

  try {
    // Check if user already has access using admin token
    logger.info("Checking existing repository access", {
      githubUsername,
      repository: `${siteConfig.repo.owner}/${siteConfig.repo.name}`,
    });

    try {
      const response = await octokit?.rest.repos.getCollaboratorPermissionLevel({
        owner: siteConfig.repo.owner,
        repo: siteConfig.repo.name,
        username: githubUsername,
      });

      const collaborator = response?.data;

      logger.info("Retrieved collaborator permission level", {
        githubUsername,
        permission: collaborator?.permission,
      });

      if (
        collaborator?.permission === "admin" ||
        collaborator?.permission === "write" ||
        collaborator?.permission === "read"
      ) {
        logger.info("User already has repository access", {
          githubUsername,
          permission: collaborator.permission,
        });
        return true;
      }
    } catch (error) {
      // 404 is expected if user is not a collaborator yet
      if (error instanceof Error && !error.message.includes("Not Found")) {
        throw error;
      }
      logger.info("User is not a collaborator yet", { githubUsername });
    }

    // Verify user token has correct scopes
    // const userScopes = await getTokenScopes(accessToken);
    // logger.info("Verifying user token", {
    // 	githubUsername,
    // 	scopes: userScopes,
    // 	hasRepoScope: userScopes.includes("repo"),
    // });

    // if (!userScopes.includes("repo")) {
    // 	throw new Error("User token missing 'repo' scope");
    // }

    // const userOctokit = new Octokit({
    // 	auth: accessToken,
    // });

    // const { data: user } = await userOctokit.rest.users.getAuthenticated();

    // logger.info("User token verified", {
    // 	providedUsername: githubUsername,
    // 	authenticatedUsername: user.login,
    // });

    const payload = {
      owner: siteConfig.repo.owner,
      repo: siteConfig.repo.name,
      username: githubUsername,
      permission: "read",
    };

    // Add user as collaborator with write access using admin token
    logger.info("Adding user as repository collaborator", payload);

    await octokit?.rest.repos.addCollaborator(payload);

    logger.info("Successfully added user as repository collaborator", payload);

    return true;
  } catch (error) {
    logger.error("Error granting GitHub access", {
      error,
      githubUsername,
      errorMessage: error instanceof Error ? error.message : "Unknown error",
      errorStack: error instanceof Error ? error.stack : undefined,
    });
    throw error;
  }
}

/**
 * Revokes GitHub access for a user, with safeguards to prevent dangerous operations
 */
export async function revokeGitHubAccess(userId: string) {
  if (!isGitHubServiceEnabled()) {
    logger.warn("GitHub Service disabled, skipping revokeGitHubAccess.");
    return false; // Indicate failure/disabled
  }
  try {
    // Get user details including their GitHub token and username
    const user = await db?.query.users.findFirst({
      where: eq(users.id, userId),
      columns: {
        id: true,
        githubUsername: true,
        email: true,
      },
    });

    if (!user?.githubUsername) {
      logger.warn("No GitHub username found for user - cannot revoke repo access", { userId });
      return false; // Indicate no action taken (username not found)
    }

    if (siteConfig.repo.owner === user.githubUsername) {
      // Update user record
      await db
        ?.update(users)
        .set({
          githubUsername: null,
          updatedAt: new Date(),
        })
        .where(eq(users.id, userId));
      return true;
    }

    // Check if user has active deployments or critical operations
    const hasActiveDeployments = await checkActiveDeployments(user.githubUsername);
    if (hasActiveDeployments) {
      throw new Error("Cannot revoke access while user has active deployments");
    }

    logger.info("Removing user as collaborator", {
      owner: siteConfig.repo.owner,
      repo: siteConfig.repo.name,
      username: user.githubUsername,
    });

    try {
      // First, check for and cancel any pending invitations
      try {
        const invitationsResponse = await octokit?.rest.repos.listInvitations({
          owner: siteConfig.repo.owner,
          repo: siteConfig.repo.name,
        });

        const pendingInvitation = invitationsResponse?.data?.find(
          (inv) => inv.invitee?.login?.toLowerCase() === user.githubUsername?.toLowerCase()
        );

        if (pendingInvitation) {
          logger.info("Found pending invitation, canceling it", {
            invitationId: pendingInvitation.id,
            username: user.githubUsername,
          });

          await octokit?.rest.repos.deleteInvitation({
            owner: siteConfig.repo.owner,
            repo: siteConfig.repo.name,
            invitation_id: pendingInvitation.id,
          });

          logger.info("Successfully canceled pending invitation", {
            invitationId: pendingInvitation.id,
            username: user.githubUsername,
          });
        }
      } catch (invError) {
        logger.warn("Error checking/canceling invitations", {
          error: invError instanceof Error ? invError.message : "Unknown error",
          username: user.githubUsername,
        });
        // Continue with removing collaborator even if invitation check fails
      }

      // Remove user as collaborator using admin token (for users who accepted)
      const response = await octokit?.rest.repos.removeCollaborator({
        owner: siteConfig.repo.owner,
        repo: siteConfig.repo.name,
        username: user.githubUsername,
      });

      // 204 = success, 404 = user was not a collaborator (might have been just invited)
      if (response?.status !== 204 && response?.status !== 404) {
        throw new Error(`Failed to remove collaborator: ${response?.status}`);
      }

      logger.info("Successfully removed user as collaborator", {
        status: response?.status,
        username: user.githubUsername,
      });

      // If this is a stub (pending invite) record, delete it; otherwise just clear the username
      if (user.email === pendingCollaboratorEmail(user.githubUsername)) {
        await db?.delete(users).where(eq(users.id, userId));
        logger.info("Deleted stub collaborator record", {
          userId,
          githubUsername: user.githubUsername,
        });
      } else {
        await db
          ?.update(users)
          .set({ githubUsername: null, updatedAt: new Date() })
          .where(eq(users.id, userId));
      }

      logger.info("Successfully revoked GitHub access", {
        userId,
        githubUsername: user.githubUsername,
      });
    } catch (removeError) {
      logger.error("Failed to remove GitHub collaborator", {
        error: removeError instanceof Error ? removeError.message : "Unknown error",
        username: user.githubUsername,
      });
      throw removeError;
    }
  } catch (error) {
    logger.error("Failed to revoke GitHub access", {
      userId,
      error: error instanceof Error ? error.message : "Unknown error",
    });
    throw error;
  }
}

/**
 * Checks if a GitHub user has any active deployments or critical operations
 */
async function checkActiveDeployments(githubUsername: string): Promise<boolean> {
  if (!isGitHubServiceEnabled()) {
    logger.debug("GitHub Service disabled, skipping checkActiveDeployments.");
    return true; // Assume no active deployments if service is off
  }

  if (!env?.GITHUB_ACCESS_TOKEN) {
    logger.warn("GITHUB_ACCESS_TOKEN is not set in the environment.");
    return false;
  }

  try {
    const octokit = new Octokit({
      auth: env.GITHUB_ACCESS_TOKEN,
    });

    // Check deployments
    const { data: deployments } = await octokit.rest.repos.listDeployments({
      owner: siteConfig.repo.owner,
      repo: siteConfig.repo.name,
      per_page: 100,
    });

    const activeDeployments = deployments.filter(
      (deployment: any) => deployment.creator?.login === githubUsername
    );

    return activeDeployments.length > 0;
  } catch (error) {
    logger.error("Failed to check active deployments", {
      githubUsername,
      error: error instanceof Error ? error.message : "Unknown error",
    });
    return false;
  }
}

/**
 * Get OAuth token scopes
 */
async function getTokenScopes(token: string): Promise<string[]> {
  if (!isGitHubServiceEnabled()) {
    logger.debug("GitHub Service disabled, skipping getTokenScopes.");
    return [];
  }
  try {
    // Temporarily create an octokit instance for this check if needed,
    // or rely on the main octokit instance if it's guaranteed to be valid here.
    const tempOctokit = new Octokit({ auth: token });
    const response = await tempOctokit.request("GET /");
    return response.headers["x-oauth-scopes"]?.split(", ") ?? [];
  } catch (error) {
    logger.error("Error getting token scopes", { error });
    return [];
  }
}

/**
 * Check if a GitHub username exists
 */
export async function checkGitHubUsername(username: string): Promise<boolean> {
  if (!isGitHubServiceEnabled()) {
    logger.debug("GitHub Service disabled, skipping checkGitHubUsername.");
    return true; // Or false? Depending on desired behavior when disabled.
  }
  logger.info("Checking if GitHub username exists", { username });

  try {
    await octokit?.rest.users.getByUsername({
      username,
    });
    logger.info("GitHub username exists", { username });
    return true;
  } catch (error) {
    logger.error("Error checking GitHub username", {
      error,
      username,
      errorMessage: error instanceof Error ? error.message : "Unknown error",
    });
    return false;
  }
}

// Cache the star count for 5 minutes to avoid hitting GitHub's rate limits
export const getRepoStars = cache(
  async ({
    owner = siteConfig.repo.owner,
    repo = siteConfig.repo.name,
  }: {
    owner?: string;
    repo?: string;
  } = {}) => {
    if (!isGitHubServiceEnabled()) {
      logger.debug("GitHub Service disabled, skipping getRepoStars.");
      return 0;
    }
    try {
      const response = await getRepo(owner, repo);
      return response?.stargazers_count ?? 0;
    } catch (error) {
      logger.warn("Error fetching GitHub stars:", error);
      return 0;
    }
  }
);

/**
 * Verify and store a GitHub username for a user
 * This is a simplified version that just verifies the username exists and stores it
 */
export async function verifyAndStoreGitHubUsername(
  userId: string,
  username: string
): Promise<boolean> {
  if (!isGitHubServiceEnabled()) {
    logger.warn("GitHub Service disabled, skipping verifyAndStoreGitHubUsername.");
    return false; // Cannot verify or store if service is disabled
  }
  logger.info("Verifying and storing GitHub username", { userId, username });

  try {
    // First verify the username exists on GitHub
    const exists = await checkGitHubUsername(username);
    if (!exists) {
      logger.error("GitHub username does not exist", { username });
      throw new Error("GitHub username does not exist");
    }

    await grantGitHubAccess({ githubUsername: username });

    // Update the user record with the GitHub username
    await db
      ?.update(users)
      .set({
        githubUsername: username,
        updatedAt: new Date(),
      })
      .where(eq(users.id, userId));

    logger.info("Successfully stored GitHub username", { userId, username });
    return true;
  } catch (error) {
    logger.error("Error verifying and storing GitHub username", {
      error,
      userId,
      username,
      errorMessage: error instanceof Error ? error.message : "Unknown error",
    });
    throw error;
  }
}

/**
 * Gets detailed information about repository collaborators
 */
export async function getCollaboratorDetails(username: string): Promise<GitHubProfile | null> {
  if (!isGitHubServiceEnabled()) {
    logger.debug("GitHub Service disabled, skipping getCollaboratorDetails.");
    return null;
  }
  if (!username) {
    logger.warn("getCollaboratorDetails called with empty username");
    return null;
  }

  try {
    // Get collaborator permission level
    const collaboratorResponse = await octokit?.rest.repos.getCollaboratorPermissionLevel({
      owner: siteConfig.repo.owner,
      repo: siteConfig.repo.name,
      username,
    });
    const collaborator = collaboratorResponse?.data;

    // Get user profile information
    const profileResponse = await octokit?.rest.users.getByUsername({
      username,
    });
    const profile = profileResponse?.data;

    if (!profile || !collaborator?.permission) {
      return null;
    }

    return {
      login: profile.login,
      avatar_url: profile.avatar_url,
      html_url: profile.html_url,
      name: profile.name || profile.login,
      bio: profile.bio || "",
      company: profile.company,
      blog: profile.blog || "",
      location: profile.location,
      email: profile.email,
      public_repos: profile.public_repos,
      followers: profile.followers,
      following: profile.following,
      permission: collaborator.permission,
    };
  } catch (error) {
    logger.error("Error fetching collaborator details:", error);
    return null;
  }
}

/**
 * GitHub download service
 *
 * Downloads the latest release from the GitHub repository
 * and caches it for 1 hour
 */

import { createWriteStream } from "fs";
import { mkdir, readFile, stat, writeFile } from "fs/promises";
import https from "https";
import { tmpdir } from "os";
import { join } from "path";
import { pipeline } from "stream/promises";
import { siteConfig } from "@/config/site-config";
import { env } from "@/env";
import { logger } from "@/lib/logger";

// Use a writable cache directory on serverless (e.g. Vercel) and a local dir in dev
const DEFAULT_CACHE_DIR = join(process.cwd(), ".cache", "downloads");
const RUNTIME_CACHE_DIR = join(tmpdir(), "shipkit", "downloads");
const CACHE_DIR = process.env.VERCEL ? RUNTIME_CACHE_DIR : DEFAULT_CACHE_DIR;
const CACHE_DURATION = 1000 * 60 * 60; // 1 hour

interface DownloadMetadata {
  url: string;
  timestamp: number;
  version: string;
}

/**
 * Make an authenticated GitHub API request with redirect following
 */
async function makeGitHubRequest(url: string): Promise<{
  statusCode: number;
  headers: Record<string, string | string[] | undefined>;
  data: any;
}> {
  return new Promise((resolve, reject) => {
    const makeRequest = (requestUrl: string) => {
      const headers: Record<string, string> = {
        "User-Agent": "Shipkit-Downloader",
        Accept: "application/vnd.github.v3+json",
      };
      if (env?.GITHUB_ACCESS_TOKEN) {
        headers.Authorization = `Bearer ${env.GITHUB_ACCESS_TOKEN}`;
      }

      https
        .get(requestUrl, { headers }, (response) => {
          if (
            response.statusCode === 301 ||
            response.statusCode === 302 ||
            response.statusCode === 307
          ) {
            const redirectUrl = response.headers.location;
            if (!redirectUrl) {
              reject(new Error("Redirect location not found"));
              return;
            }
            makeRequest(redirectUrl);
            return;
          }

          let data = "";
          response.on("data", (chunk) => {
            data += chunk;
          });

          response.on("end", () => {
            try {
              resolve({
                statusCode: response.statusCode || 500,
                headers: response.headers,
                data: data ? JSON.parse(data) : null,
              });
            } catch (e) {
              reject(new Error("Failed to parse response"));
            }
          });
        })
        .on("error", reject);
    };

    makeRequest(url);
  });
}

/**
 * Verify GitHub token has required permissions for private repository access
 */
async function verifyTokenPermissions(): Promise<{
  isValid: boolean;
  scopes?: string[];
  error?: string;
}> {
  try {
    const apiUrl = `https://api.github.com/repos/${siteConfig.repo.owner}/${siteConfig.repo.name}`;
    const { statusCode, headers, data } = await makeGitHubRequest(apiUrl);

    // Check OAuth scopes
    const scopes = headers["x-oauth-scopes"]?.toString().split(", ");
    if (env?.GITHUB_ACCESS_TOKEN) {
      logger.info("GitHub token scopes", { scopes });
    }

    // Public repos will return 200 without a token
    if (statusCode === 200) {
      return { isValid: true, scopes };
    }

    logger.error("GitHub repository accessibility check failed", {
      statusCode,
      headers,
      data,
    });

    return {
      isValid: false,
      scopes,
      error: data?.message || "Unknown error",
    };
  } catch (error) {
    logger.error("GitHub repository accessibility request failed", { error });
    return {
      isValid: false,
      error: error instanceof Error ? error.message : "Unknown error",
    };
  }
}

/**
 * Ensures the cache directory exists
 */
async function ensureCacheDir() {
  try {
    await stat(CACHE_DIR);
  } catch {
    await mkdir(CACHE_DIR, { recursive: true });
  }
}

/**
 * Gets the cached file path for a given version
 */
function getCacheFilePath(version: string) {
  return join(CACHE_DIR, `shipkit-${version}.zip`);
}

/**
 * Gets the metadata file path
 */
function getMetadataPath() {
  return join(CACHE_DIR, "metadata.json");
}

/**
 * Reads the metadata file
 */
async function readMetadata(): Promise<DownloadMetadata | null> {
  try {
    const metadataPath = getMetadataPath();
    const content = await readFile(metadataPath, "utf-8");
    return JSON.parse(content);
  } catch {
    return null;
  }
}

/**
 * Writes metadata to the cache
 */
async function writeMetadata(metadata: DownloadMetadata) {
  const metadataPath = getMetadataPath();
  await writeFile(metadataPath, JSON.stringify(metadata, null, 2));
}

/**
 * Downloads a file from a URL to a local path
 */
async function downloadFile(url: string, filePath: string): Promise<void> {
  return new Promise((resolve, reject) => {
    const makeRequest = (requestUrl: string) => {
      const headers: Record<string, string> = {
        "User-Agent": "Shipkit-Downloader",
        Accept: "application/vnd.github.v3+json",
      };
      if (env?.GITHUB_ACCESS_TOKEN) {
        headers.Authorization = `Bearer ${env.GITHUB_ACCESS_TOKEN}`;
      }

      https
        .get(requestUrl, { headers }, (response) => {
          if (
            response.statusCode === 301 ||
            response.statusCode === 302 ||
            response.statusCode === 307
          ) {
            const redirectUrl = response.headers.location;
            if (!redirectUrl) {
              reject(new Error("Redirect location not found"));
              return;
            }
            makeRequest(redirectUrl);
            return;
          }

          if (response.statusCode !== 200) {
            let data = "";
            response.on("data", (chunk) => {
              data += chunk;
            });
            response.on("end", () => {
              try {
                const errorDetails = JSON.parse(data);
                logger.error("GitHub API error details", {
                  errorDetails,
                  statusCode: response.statusCode,
                  headers: response.headers,
                  url: requestUrl,
                });
              } catch (e) {
                logger.error("Failed to parse GitHub API error response", {
                  data,
                  error: e,
                });
              }
              reject(
                new Error(`Failed to download: ${response.statusCode} - ${response.statusMessage}`)
              );
            });
            return;
          }

          const fileStream = createWriteStream(filePath);
          pipeline(response, fileStream)
            .then(() => resolve())
            .catch(reject);
        })
        .on("error", (error) => {
          logger.error("Download request failed", { error, url: requestUrl });
          reject(error);
        });
    };

    makeRequest(url);
  });
}

/**
 * Repackage a GitHub zipball so the root directory uses a clean name
 * instead of the default "owner-repo-sha" format.
 *
 * Uses JSZip for portability (no shell dependency on unzip/zip).
 */
async function repackageZip(filePath: string): Promise<void> {
  const targetName = siteConfig.title.toLowerCase();

  try {
    const JSZip = (await import("jszip")).default;
    const zipData = await readFile(filePath);
    const zip = await JSZip.loadAsync(zipData);

    // GitHub zipballs have a single root dir like "owner-repo-sha/"
    const allPaths = Object.keys(zip.files);
    const rootPrefix = allPaths[0]?.split("/")[0];

    if (!rootPrefix || rootPrefix === targetName) {
      return; // Already clean or can't determine root
    }

    // Rebuild zip with renamed root directory
    const newZip = new JSZip();
    for (const [path, file] of Object.entries(zip.files)) {
      const newPath = path.replace(rootPrefix, targetName);
      if (file.dir) {
        newZip.folder(newPath);
      } else {
        const content = await file.async("nodebuffer");
        newZip.file(newPath, content);
      }
    }

    const output = await newZip.generateAsync({
      type: "nodebuffer",
      compression: "DEFLATE",
      compressionOptions: { level: 6 },
    });

    await writeFile(filePath, output);
    logger.info("Repackaged zip with clean root directory", { from: rootPrefix, to: targetName });
  } catch (err) {
    logger.warn("Failed to repackage zip, using original", { error: err });
  }
}

/**
 * Downloads the latest release
 */
async function downloadLatestRelease(): Promise<{
  filePath: string;
  version: string;
}> {
  await ensureCacheDir();

  // First, verify token permissions
  const { isValid, scopes, error } = await verifyTokenPermissions();
  if (!isValid) {
    throw new Error(
      `GitHub token verification failed: ${error}. Required scopes: repo. Current scopes: ${
        scopes?.join(", ") || "none"
      }`
    );
  }

  try {
    // Use the main branch as version since we're not using releases
    const version = "main";
    const filePath = getCacheFilePath(version);

    // Check if we already have this version cached
    try {
      await stat(filePath);
      logger.info("Using cached archive", { version });
      return { filePath, version };
    } catch {
      // File doesn't exist, continue with download
    }

    // Download using GitHub API
    logger.info("Downloading repository archive", { version });
    const downloadUrl = `https://api.github.com/repos/${siteConfig.repo.owner}/${siteConfig.repo.name}/zipball/main`;

    logger.info("Starting download", { url: downloadUrl });
    await downloadFile(downloadUrl, filePath);

    // Repackage to use clean directory name instead of "lacymorrow-shipkit-<sha>"
    await repackageZip(filePath);

    // Update metadata
    await writeMetadata({
      url: downloadUrl,
      timestamp: Date.now(),
      version,
    });

    return { filePath, version };
  } catch (error) {
    logger.error("Error downloading archive", { error });
    throw error;
  }
}

/**
 * Gets the path to the latest ZIP file
 * Downloads it if necessary or if cache is expired
 */
export async function getLatestReleaseFile(): Promise<string> {
  const metadata = await readMetadata();
  const cacheExpired = !metadata || Date.now() - metadata.timestamp > CACHE_DURATION;

  if (cacheExpired) {
    logger.info("Cache expired, downloading new archive");
    const { filePath } = await downloadLatestRelease();
    return filePath;
  }

  const filePath = getCacheFilePath(metadata.version);
  try {
    await stat(filePath);
    logger.info("Using cached archive", { version: metadata.version });
    return filePath;
  } catch {
    // File missing, download again
    logger.info("Cache file missing, downloading new archive");
    const { filePath: newPath } = await downloadLatestRelease();
    return newPath;
  }
}

