    if (!githubAccount?.access_token) {
      return new NextResponse("GitHub account not connected", { status: 400 });
    }

    const { template } = await request.json();

    const octokit = new Octokit({
      auth: githubAccount.access_token,
    });

    // Create repository from template
    const response = await octokit.repos.createUsingTemplate({
      template_owner: template.owner,
      template_repo: template.name,
      name: template.name,
      private: true,
      description: "My Shipkit instance",
    });

    return NextResponse.json({
      url: response.data.html_url,
      name: response.data.name,
      fullName: response.data.full_name,
    });
  } catch (error) {
    console.error("Error creating repository:", error);
    return new NextResponse(
      error instanceof Error ? error.message : "Failed to create repository",
      { status: 500 }
    );
  }
}

/**
 * Generate suggested project names based on repository name
 */
export function generateProjectNameSuggestions(repoName: string): string[] {
  const sanitized = repoName.toLowerCase().replace(/[^a-z0-9]/g, "-");
  const suggestions = [
    sanitized,
    `${sanitized}-app`,
    `${sanitized}-web`,
    `${sanitized}-site`,
    `my-${sanitized}`,
  ];

  // Remove duplicates and invalid names
  return [...new Set(suggestions)].filter(
    (name) =>
      name.length <= 52 &&
      /^[a-z0-9-]+$/.test(name) &&
      !name.startsWith("-") &&
      !name.endsWith("-") &&
      !name.includes("--")
  );
}
